import{_ as n,o as i,c as t,an as r}from"./chunks/framework.D5fFzH9V.js";const c=JSON.parse('{"title":"Unser Vesting-Vertrag","description":"Erklärung und Auszug der Vesting-Vereinbarung der Syslifters-Gründer (Vesting-Zeitraum, Einziehung/Clawback bei vorzeitigem Ausstieg).","frontmatter":{"title":"Unser Vesting-Vertrag","description":"Erklärung und Auszug der Vesting-Vereinbarung der Syslifters-Gründer (Vesting-Zeitraum, Einziehung/Clawback bei vorzeitigem Ausstieg)."},"headers":[],"relativePath":"de/vesting-vertrag.md","filePath":"de/vesting-vertrag.md"}'),s={name:"de/vesting-vertrag.md"};function a(d,e,g,l,u,o){return i(),t("div",null,[...e[0]||(e[0]=[r(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /de/vesting-vertrag.md for this page in Markdown format</div><h1 id="unser-vesting-vertrag" tabindex="-1">Unser Vesting-Vertrag <a class="header-anchor" href="#unser-vesting-vertrag" aria-label="Permalink to &quot;Unser Vesting-Vertrag&quot;">​</a></h1><p>Wir sind vier Gründer und haben als Holdings jeweils eine Ein-Personen-GmbH gegründet, die wiederum die Syslifters GmbH als gemeinsame Betriebs-GmbH gegründet haben (siehe auch <a href="/">hier</a>).<br> Das Risiko, dass jemand nicht mehr mag und aussteigt gibt es natürlich. Dafür haben wir eine &quot;Vesting-Vereinbarung&quot; geschlossen.</p><p>Wir haben uns dabei verpflichtet, zumindest drei Jahre dabeizubleiben und aktiv mitzuarbeiten.<br> Wer früher aussteigt, verliert aliquot Geschäftsanteile.</p><p>???+ abstact &quot;Unser Vesting-Vertrag&quot;<br> Die Geschäftsanteile der EIGENTÜMER an der GESELLSCHAFT unterliegen einem Vesting. Stellt eine der NATÜRLICHEN PERSONEN ihre ganze Arbeitskraft im Ausmaß von mindestens 30 Wochenstunden (gerechnet auf den Jahresdurchschnitt des Wirtschaftsjahres) nicht mehr der GESELLSCHAFT uneingeschränkt zur Verfügung und ist die von ihr sonst ausgeübte Tätigkeit keine Tätigkeit im Interesse der GESELLSCHAFT, ist die GESELLSCHAFT berechtigt, die Geschäftsanteile des von ihr kontrollierten EIGENTÜMERs ganz oder teilweise gegen Rückzahlung der aliquoten Stammkapitaleinlage einzuziehen.</p><pre><code>Entsprechende Optionsvereinbarungen sollen insbesondere vorsehen: Der Anteil der der Einziehung unterliegenden Geschäftsanteile reduziert sich um 1/36 für jeden seit dem 01.05.2022 vollendeten Monat. Dementsprechend behalten die EIGENTÜMER jeweils 100 % ihrer Geschäftsanteile an der GESELLSCHAFT, sofern die aktive Tätigkeit der den EIGENTÜMER kontrollierenden NATÜRLICHEN PERSON für die GESELLSCHAFT jeweils mindestens bis zum 01.05.2025 aufrechterhalten wird. Im Falle eines Liquidationsereignisses vor dem 01.05.2025 gelten sämtliche Geschäftsanteile mit dem Wirksamwerden eines solchen Ereignisses als gevestet (Accelerated Vesting) mit der Folge, dass eine Einziehung danach nicht mehr möglich ist.
</code></pre>`,6)])])}const m=n(s,[["render",a]]);export{c as __pageData,m as default};
